-- Tiered milestone-achievements: 100 onderwerpen x 4 tiers (Brons/Zilver/Goud/Platinum)
-- = 400 badges. Bron: Achievements ZWB home.xlsx.
--
-- Bestaande "weekly" badges (climber_week, distance_week, kudos_received_week,
-- consistency_week) blijven werken — die krijgen kind='weekly'.

-- 1. Schema-uitbreiding achievement_badges
alter table public.achievement_badges
  add column if not exists kind text not null default 'weekly'
    check (kind in ('weekly','milestone')),
  add column if not exists achievement_code text,
  add column if not exists tier text
    check (tier in ('bronze','silver','gold','platinum')),
  add column if not exists visual_hint text,
  add column if not exists trigger_source text not null default 'manual'
    check (trigger_source in ('auto','manual','future')),
  add column if not exists trigger_config jsonb not null default '{}'::jsonb,
  add column if not exists sort_order int not null default 0;

create index if not exists achievement_badges_code_tier_idx
  on public.achievement_badges (achievement_code, tier);
create index if not exists achievement_badges_sort_idx
  on public.achievement_badges (sort_order);

-- 2. Schema-uitbreiding achievement_awards
alter table public.achievement_awards
  add column if not exists award_scope text not null default 'weekly'
    check (award_scope in ('weekly','milestone'));

-- Voor milestone-awards: één award per (badge, profiel). Weekly behoudt
-- (badge, profiel, period_start) als uniek-key.
create unique index if not exists achievement_awards_milestone_unique_idx
  on public.achievement_awards (badge_id, profile_id)
  where award_scope = 'milestone';

-- 3. Bestaande weekly badges expliciet markeren
update public.achievement_badges
set kind = 'weekly', trigger_source = 'auto'
where id in ('climber_week','distance_week','kudos_received_week','consistency_week');

-- 4. Seed 400 milestone-badges
